// Validate Twilio webhook signature (X-Twilio-Signature) to prevent spoofed requests.
// Skips validation when MESSAGING_PROVIDER is not 'twilio'.
const crypto = require('crypto');
const msgProvider = $env.MESSAGING_PROVIDER || 'twilio';
const input = $input.first().json;

if (msgProvider !== 'twilio') {
  // Non-Twilio provider — skip signature check
  return [{ json: input }];
}

const TWILIO_AUTH_TOKEN = $env.TWILIO_AUTH_TOKEN;
if (!TWILIO_AUTH_TOKEN) throw new Error('Missing required env var: TWILIO_AUTH_TOKEN');

// n8n webhook exposes headers on the input json
const headers = input.headers || {};
const twilioSignature = headers['x-twilio-signature'] || headers['X-Twilio-Signature'] || '';
if (!twilioSignature) throw new Error('Missing X-Twilio-Signature header — request rejected');

// Build the validation string: full webhook URL + sorted POST params appended
const WEBHOOK_BASE_URL = $env.N8N_WEBHOOK_BASE_URL || $env.WEBHOOK_URL || '';
if (!WEBHOOK_BASE_URL) throw new Error('Missing required env var: N8N_WEBHOOK_BASE_URL — needed for Twilio signature validation');

const webhookPath = 'inbound-sms';
const fullUrl = WEBHOOK_BASE_URL.replace(/\/$/, '') + '/webhook/' + webhookPath;

// Twilio sends form-encoded POST params in body
const body = input.body || input;
const paramKeys = Object.keys(body).filter(k => k !== 'headers' && k !== 'webhookUrl').sort();
let dataString = fullUrl;
for (const key of paramKeys) {
  dataString += key + (body[key] != null ? String(body[key]) : '');
}

const computed = crypto
  .createHmac('sha1', TWILIO_AUTH_TOKEN)
  .update(dataString)
  .digest('base64');

// Timing-safe comparison
const expected = Buffer.from(twilioSignature);
const actual = Buffer.from(computed);
if (expected.length !== actual.length || !crypto.timingSafeEqual(expected, actual)) {
  throw new Error('Invalid Twilio webhook signature — request rejected');
}

return [{ json: input }];

// Parse inbound message from Twilio or GHL webhook into normalized format
const msgProvider = $env.MESSAGING_PROVIDER || 'twilio';
const input = $input.first().json;
const body = input.body || input;

let fromPhone = '';
let toPhone = '';
let messageBody = '';
let inboundContactId = null;

if (msgProvider === 'ghl') {
  // GHL inbound webhook format
  fromPhone = (body.phone || body.contactPhone || body.from || '').replace(/[^\d+]/g, '');
  toPhone = (body.to || body.locationPhone || '').replace(/[^\d+]/g, '');
  messageBody = body.message || body.body || body.text || '';
  inboundContactId = body.contactId || body.contact_id || null;
} else {
  // Default: Twilio webhook format
  fromPhone = (body.From || '').replace(/[^\d+]/g, '');
  toPhone = (body.To || '').replace(/[^\d+]/g, '');
  messageBody = body.Body || '';
}

if (!fromPhone) throw new Error('No From phone number in webhook payload');

return [{ json: { fromPhone, toPhone, messageBody, inboundContactId, _msgProvider: msgProvider, timestamp: new Date().toISOString() } }];

// Lookup lead in CRM — supports Activix and GHL
const provider = $env.CRM_PROVIDER || 'activix';
const input = $input.first().json;
const fromPhone = input.fromPhone;
const inboundContactId = input.inboundContactId;

function getCrmConfig() {
  if (provider === 'ghl') {
    return {
      baseUrl: 'https://services.leadconnectorhq.com',
      headers: { 'Authorization': `Bearer ${$env.GHL_API_KEY || (() => { throw new Error('Missing required env var: GHL_API_KEY'); })()}`, 'Version': '2021-07-28', 'Accept': 'application/json' },
    };
  }
  return {
    baseUrl: $env.ACTIVIX_API_URL || 'https://api.crm.activix.ca/v2',
    headers: { 'Authorization': `Bearer ${$env.ACTIVIX_API_TOKEN || (() => { throw new Error('Missing required env var: ACTIVIX_API_TOKEN'); })()}`, 'Accept': 'application/json' },
  };
}

const config = getCrmConfig();
let lead = null;
let leadName = 'Unknown';
let leadId = null;
let locale = 'en-CA';
let advisorName = null;

try {
  if (provider === 'ghl') {
    // GHL: lookup by contactId if available, otherwise search by phone
    if (inboundContactId) {
      const resp = await fetch(`${config.baseUrl}/contacts/${inboundContactId}`, { headers: config.headers });
      if (resp.ok) {
        const data = await resp.json();
        lead = data.contact || data;
      }
    }
    if (!lead) {
      const GHL_LOCATION_ID = $env.GHL_LOCATION_ID || '';
      const resp = await fetch(`${config.baseUrl}/contacts/search/duplicate?locationId=${GHL_LOCATION_ID}&phone=${encodeURIComponent(fromPhone)}`, { headers: config.headers });
      if (resp.ok) {
        const data = await resp.json();
        if (data.contact) lead = data.contact;
      }
    }
    if (lead) {
      leadId = lead.id || lead.contactId;
      leadName = `${lead.firstName || lead.first_name || ''} ${lead.lastName || lead.last_name || ''}`.trim() || 'Unknown';
      locale = lead.tags?.includes('french') ? 'fr-CA' : 'en-CA';
      advisorName = lead.assignedTo || null;
      // Normalize lead to common format for downstream nodes
      lead = {
        ...lead,
        id: leadId,
        first_name: lead.firstName || lead.first_name || null,
        last_name: lead.lastName || lead.last_name || null,
        locale: locale,
        phones: lead.phone ? [{ number: lead.phone }] : [],
        emails: lead.email ? [{ address: lead.email }] : [],
        vehicles: [],
        advisor: advisorName ? { first_name: advisorName, name: advisorName } : null,
        consent_type: 'implied',
        consent_date: lead.dateAdded || null,
        unsubscribe_sms_date: lead.dndSettings?.SMS?.status === 'active' ? new Date().toISOString() : null,
        unsubscribe_all_date: lead.dnd ? new Date().toISOString() : null,
        _provider: 'ghl',
      };
    }
  } else {
    // Default: Activix search
    const resp = await fetch(`${config.baseUrl}/leads/search?query=${encodeURIComponent(fromPhone)}`, { headers: config.headers });
    if (resp.ok) {
      const data = await resp.json();
      if (data.data?.length > 0) {
        lead = data.data[0];
        lead._provider = 'activix';
      }
    }
    if (lead) {
      leadId = lead.id;
      leadName = `${lead.first_name || ''} ${lead.last_name || ''}`.trim() || 'Unknown';
      locale = lead.locale || 'en-CA';
      advisorName = lead.advisor?.first_name || null;
    }
  }
} catch (err) {
  console.error('CRM search failed:', err.message);
}

return [{ json: { ...input, lead, leadFound: !!lead, leadId, leadName, locale, advisorName, _crmProvider: provider } }];

const input = $input.first().json;
const leadId = input.leadId;
const staticData = $getWorkflowStaticData('global');
if (!staticData.transcripts) staticData.transcripts = {};
const transcript = staticData.transcripts[leadId] || { leadId, messages: [], touchNumber: 0, lastContactDate: null };
transcript.messages.push({ role: 'customer', content: input.messageBody, channel: 'sms', timestamp: input.timestamp });
transcript.lastContactDate = input.timestamp;
staticData.transcripts[leadId] = transcript;
return [{ json: { ...input, transcript, touchNumber: transcript.touchNumber, conversationLength: transcript.messages.length } }];

const input = $input.first().json;
const msg = (input.messageBody || '').toLowerCase();
const rules = [
  { intent:'HUMAN_REQUEST', keywords:['talk to someone','real person','parler a quelquun','speak to','manager','representative'], confidence:0.95, action:'handoff' },
  { intent:'FRUSTRATION', keywords:['angry','frustrated','terrible','worst','horrible','furieux','ridiculous','unacceptable'], confidence:0.90, action:'handoff' },
  { intent:'NOT_INTERESTED', keywords:['not interested','remove me','stop','unsubscribe','pas interesse','arretez','leave me alone','no thanks'], confidence:0.95, action:'stop' },
  { intent:'PRICE_INQUIRY', keywords:['how much','price','cost','prix','combien','pricing','msrp'], confidence:0.85, action:'handoff' },
  { intent:'TEST_DRIVE_REQUEST', keywords:['test drive','come see','essai routier','come in','visit','see the car','book appointment'], confidence:0.90, action:'handoff' },
  { intent:'FINANCING_QUESTION', keywords:['finance','payment','lease','financement','monthly','mensuel','credit','loan','down payment'], confidence:0.85, action:'handoff' },
  { intent:'TRADE_IN_REQUEST', keywords:['trade in','trade-in','my car','echange','my vehicle','mon char'], confidence:0.85, action:'handoff' },
  { intent:'TIMELINE_MENTION', keywords:['this week','today','soon','cette semaine','tomorrow','demain','this weekend','asap','this month'], confidence:0.85, action:'handoff' },
  { intent:'OBJECTION', keywords:['too expensive','better deal','trop cher','cheaper','moins cher','competitor','other dealer','negotiate'], confidence:0.80, action:'handoff' }
];
let matched = null;
for (const r of rules) { for (const kw of r.keywords) { if (msg.includes(kw)) { matched = r; break; } } if (matched) break; }
const result = matched ? { intent:matched.intent, confidence:matched.confidence, action:matched.action } : { intent:'INFO_REQUEST', confidence:0.60, action:'continue' };
result.shouldHandoff = result.action === 'handoff';
return [{ json: { ...input, intentClassification: result } }];

const input = $input.first().json;
const transcript = input.transcript || { messages: [] };
const summary = transcript.messages.slice(-10).map(m => `${m.role === 'customer' ? 'Customer' : 'AI'}: ${m.content}`).join('\n');
const ratingMap = { TEST_DRIVE_REQUEST:5, TIMELINE_MENTION:5, PRICE_INQUIRY:4, FINANCING_QUESTION:4, TRADE_IN_REQUEST:4, OBJECTION:4, FRUSTRATION:5, HUMAN_REQUEST:4 };
const actionMap = { TEST_DRIVE_REQUEST:'Book test drive immediately', TIMELINE_MENTION:'Reach out ASAP - buying signal', PRICE_INQUIRY:'Prepare pricing with incentives', FINANCING_QUESTION:'Connect with F&I department', TRADE_IN_REQUEST:'Schedule appraisal', OBJECTION:'Prepare competitive analysis', FRUSTRATION:'Manager call - immediate escalation', HUMAN_REQUEST:'Call customer directly' };
const vehicles = (input.lead?.vehicles || []).map(v => `${v.year||''} ${v.make||''} ${v.model||''}`.trim()).filter(Boolean);
return [{ json: { ...input, handoffPayload: { customerName:input.leadName, phone:input.fromPhone, vehiclesOfInterest: vehicles.length > 0 ? vehicles : ['Unknown'], conversationSummary:summary, intent:input.intentClassification.intent, confidence:input.intentClassification.confidence, rating: ratingMap[input.intentClassification.intent] || 3, touchNumber:input.touchNumber, recommendedAction: actionMap[input.intentClassification.intent] || 'Follow up', timestamp:input.timestamp } } }];

// Update CRM with handoff status — supports Activix and GHL
const provider = $env.CRM_PROVIDER || 'activix';
const input = $input.first().json;
const leadId = input.leadId;
const handoff = input.handoffPayload;

function getCrmConfig() {
  if (provider === 'ghl') {
    return {
      baseUrl: 'https://services.leadconnectorhq.com',
      headers: { 'Authorization': `Bearer ${$env.GHL_API_KEY || (() => { throw new Error('Missing required env var: GHL_API_KEY'); })()}`, 'Version': '2021-07-28', 'Content-Type': 'application/json', 'Accept': 'application/json' },
    };
  }
  return {
    baseUrl: $env.ACTIVIX_API_URL || 'https://api.crm.activix.ca/v2',
    headers: { 'Authorization': `Bearer ${$env.ACTIVIX_API_TOKEN || (() => { throw new Error('Missing required env var: ACTIVIX_API_TOKEN'); })()}`, 'Content-Type': 'application/json', 'Accept': 'application/json' },
  };
}

const config = getCrmConfig();
let updateResult = { success: false, error: null };

try {
  if (provider === 'ghl') {
    const response = await fetch(`${config.baseUrl}/contacts/${leadId}`, {
      method: 'PUT',
      headers: config.headers,
      body: JSON.stringify({
        tags: [...(input.lead?._raw?.tags || []), 'nexus-handoff', `intent-${handoff.intent.toLowerCase()}`],
        customFields: [
          { key: 'nexus_handoff_intent', value: handoff.intent },
          { key: 'nexus_handoff_action', value: handoff.recommendedAction },
          { key: 'nexus_handoff_rating', value: String(handoff.rating) },
          { key: 'nexus_handoff_date', value: new Date().toISOString() },
        ],
      }),
    });
    if (response.ok) updateResult = { success: true, error: null };
    else { const errText = await response.text(); throw new Error(`GHL error: ${response.status} ${errText}`); }

    // Add note
    try {
      await fetch(`${config.baseUrl}/contacts/${leadId}/notes`, {
        method: 'POST',
        headers: config.headers,
        body: JSON.stringify({ body: `[AI Handoff] ${handoff.intent} | ${handoff.recommendedAction}` }),
      });
    } catch (e) { /* non-critical */ }
  } else {
    // Activix PUT
    const response = await fetch(`${config.baseUrl}/leads/${leadId}`, {
      method: 'PUT',
      headers: config.headers,
      body: JSON.stringify({
        rating: handoff.rating,
        result: 'reached',
        comment: `[AI Handoff] ${handoff.intent} | ${handoff.recommendedAction}`,
      }),
    });
    if (response.ok) updateResult = { success: true, error: null };
    else { const errText = await response.text(); throw new Error(`Activix error: ${response.status} ${errText}`); }
  }
} catch (err) {
  updateResult = { success: false, error: err.message };
}

return [{ json: { ...input, _crmHandoffResult: updateResult } }];

const input = $input.first().json;
const isFrench = (input.locale || 'en-CA').startsWith('fr');
const name = input.lead?.first_name || '';
let reply = '';
if (isFrench) {
  reply = name ? `Merci pour votre message, ${name}! Je serais heureux de vous aider. Laissez-moi verifier cela pour vous.` : 'Merci pour votre message! Je serais heureux de vous aider.';
} else {
  reply = name ? `Thanks for your message, ${name}! Happy to help. Let me look into it and get right back to you.` : 'Thanks for your message! Happy to help. Let me look into it and get right back to you.';
}
return [{ json: { ...input, generatedReply: reply } }];

const input = $input.first().json;
const reply = input.generatedReply || '';
const lead = input.lead;
const violations = [];
const forbidden = [/\$\d+\/month/i, /monthly payment/i, /interest rate/i, /\d+\.?\d*\s*%\s*(apr|interest|rate)/i, /credit score/i, /paiement mensuel/i, /taux d.interet/i];
for (const p of forbidden) { if (p.test(reply)) violations.push('Forbidden financial language'); }
if (lead?.unsubscribe_sms_date) violations.push('Lead unsubscribed from SMS');
if (lead?.unsubscribe_all_date) violations.push('Lead unsubscribed from all');
if (lead?.consent_type === 'implied' && lead?.consent_date) {
  const exp = new Date(lead.consent_date); exp.setMonth(exp.getMonth() + 6);
  if (new Date() > exp) violations.push('Implied consent expired');
}
if (!reply.trim()) violations.push('Empty reply');
const pass = violations.length === 0;
let finalReply = reply;
if (pass && reply) finalReply += (input.locale || 'en-CA').startsWith('fr') ? '\n\nRepondez STOP pour ne plus recevoir de messages.' : '\n\nReply STOP to opt out.';
return [{ json: { ...input, complianceResult: { pass, violations, checkedAt: new Date().toISOString() }, finalReply: pass ? finalReply : null } }];

// Send reply SMS via configured messaging provider (Twilio or GHL)
const msgProvider = $env.MESSAGING_PROVIDER || 'twilio';
const input = $input.first().json;
const message = input.finalReply || '';
const fromPhone = input.fromPhone;
const toPhone = input.toPhone;
const contactId = input.leadId;

let sendResult = { success: false, provider: msgProvider, error: null };

try {
  if (!message) throw new Error('No message to send');

  if (msgProvider === 'ghl') {
    const GHL_API_KEY = $env.GHL_API_KEY;
    if (!GHL_API_KEY) throw new Error('Missing required env var: GHL_API_KEY');
    if (!contactId) throw new Error('No GHL contact ID for reply');
    const response = await fetch('https://services.leadconnectorhq.com/conversations/messages', {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${GHL_API_KEY}`, 'Version': '2021-07-28', 'Content-Type': 'application/json' },
      body: JSON.stringify({ type: 'SMS', contactId: contactId, message: message }),
    });
    const result = await response.json();
    if (response.ok) sendResult = { success: true, provider: 'ghl', messageId: result.messageId || result.id };
    else throw new Error(result.message || `GHL error: ${response.status}`);
  } else {
    // Default: Twilio
    const TWILIO_ACCOUNT_SID = $env.TWILIO_ACCOUNT_SID;
    const TWILIO_AUTH_TOKEN = $env.TWILIO_AUTH_TOKEN;
    if (!TWILIO_ACCOUNT_SID || !TWILIO_AUTH_TOKEN) throw new Error('Missing required env vars: TWILIO_ACCOUNT_SID and/or TWILIO_AUTH_TOKEN');
    const twilioUrl = `https://api.twilio.com/2010-04-01/Accounts/${TWILIO_ACCOUNT_SID}/Messages.json`;
    const body = new URLSearchParams({ To: fromPhone, From: toPhone, Body: message });
    const response = await fetch(twilioUrl, {
      method: 'POST',
      headers: { 'Authorization': 'Basic ' + btoa(`${TWILIO_ACCOUNT_SID}:${TWILIO_AUTH_TOKEN}`), 'Content-Type': 'application/x-www-form-urlencoded' },
      body: body.toString(),
    });
    const result = await response.json();
    if (response.ok) sendResult = { success: true, provider: 'twilio', messageId: result.sid };
    else throw new Error(result.message || `Twilio error: ${response.status}`);
  }
} catch (err) {
  sendResult = { success: false, provider: msgProvider, error: err.message };
}

return [{ json: { ...input, _smsResult: sendResult } }];

const input = $input.first().json;
const staticData = $getWorkflowStaticData('global');
if (staticData.transcripts?.[input.leadId]) {
  staticData.transcripts[input.leadId].messages.push({ role:'assistant', content:input.finalReply, channel:'sms', timestamp:new Date().toISOString() });
}
return [{ json: { status:'reply_sent', leadId:input.leadId, intent:input.intentClassification.intent } }];

const input = $input.first().json;
console.error('COMPLIANCE BLOCKED:', JSON.stringify(input.complianceResult.violations));
return [{ json: { status:'compliance_blocked', leadId:input.leadId, violations:input.complianceResult.violations, timestamp:new Date().toISOString() } }];

const input = $input.first().json;
const isFrench = (input.locale || 'en-CA').startsWith('fr');
const optOutMessage = isFrench ? 'Nous avons bien recu votre demande. Vous ne recevrez plus de messages de notre part.' : 'We have received your request. You will not receive any more messages from us.';
return [{ json: { ...input, optOutMessage } }];

// Send opt-out confirmation via configured messaging provider
const msgProvider = $env.MESSAGING_PROVIDER || 'twilio';
const input = $input.first().json;
const message = input.optOutMessage || '';
const fromPhone = input.fromPhone;
const toPhone = input.toPhone;
const contactId = input.leadId;

let sendResult = { success: false, provider: msgProvider, error: null };

try {
  if (msgProvider === 'ghl') {
    const GHL_API_KEY = $env.GHL_API_KEY;
    if (!GHL_API_KEY) throw new Error('Missing required env var: GHL_API_KEY');
    if (!contactId) throw new Error('No GHL contact ID');
    const response = await fetch('https://services.leadconnectorhq.com/conversations/messages', {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${GHL_API_KEY}`, 'Version': '2021-07-28', 'Content-Type': 'application/json' },
      body: JSON.stringify({ type: 'SMS', contactId: contactId, message: message }),
    });
    if (response.ok) sendResult = { success: true, provider: 'ghl' };
    else { const r = await response.json(); throw new Error(r.message || `GHL error: ${response.status}`); }
  } else {
    // Default: Twilio
    const TWILIO_ACCOUNT_SID = $env.TWILIO_ACCOUNT_SID;
    const TWILIO_AUTH_TOKEN = $env.TWILIO_AUTH_TOKEN;
    if (!TWILIO_ACCOUNT_SID || !TWILIO_AUTH_TOKEN) throw new Error('Missing required env vars: TWILIO_ACCOUNT_SID and/or TWILIO_AUTH_TOKEN');
    const twilioUrl = `https://api.twilio.com/2010-04-01/Accounts/${TWILIO_ACCOUNT_SID}/Messages.json`;
    const body = new URLSearchParams({ To: fromPhone, From: toPhone, Body: message });
    const response = await fetch(twilioUrl, {
      method: 'POST',
      headers: { 'Authorization': 'Basic ' + btoa(`${TWILIO_ACCOUNT_SID}:${TWILIO_AUTH_TOKEN}`), 'Content-Type': 'application/x-www-form-urlencoded' },
      body: body.toString(),
    });
    if (response.ok) sendResult = { success: true, provider: 'twilio' };
    else { const r = await response.json(); throw new Error(r.message || `Twilio error: ${response.status}`); }
  }
} catch (err) {
  sendResult = { success: false, provider: msgProvider, error: err.message };
}

return [{ json: { ...input, _optOutSmsResult: sendResult } }];

// Update CRM with opt-out status — supports Activix and GHL
const provider = $env.CRM_PROVIDER || 'activix';
const input = $input.first().json;
const leadId = input.leadId;

function getCrmConfig() {
  if (provider === 'ghl') {
    return {
      baseUrl: 'https://services.leadconnectorhq.com',
      headers: { 'Authorization': `Bearer ${$env.GHL_API_KEY || (() => { throw new Error('Missing required env var: GHL_API_KEY'); })()}`, 'Version': '2021-07-28', 'Content-Type': 'application/json', 'Accept': 'application/json' },
    };
  }
  return {
    baseUrl: $env.ACTIVIX_API_URL || 'https://api.crm.activix.ca/v2',
    headers: { 'Authorization': `Bearer ${$env.ACTIVIX_API_TOKEN || (() => { throw new Error('Missing required env var: ACTIVIX_API_TOKEN'); })()}`, 'Content-Type': 'application/json', 'Accept': 'application/json' },
  };
}

const config = getCrmConfig();
let updateResult = { success: false, error: null };

try {
  if (provider === 'ghl') {
    // GHL: enable DND for the contact
    const response = await fetch(`${config.baseUrl}/contacts/${leadId}`, {
      method: 'PUT',
      headers: config.headers,
      body: JSON.stringify({
        dnd: true,
        dndSettings: { SMS: { status: 'active', message: 'Customer opted out via automated SMS' }, Email: { status: 'active', message: 'Customer opted out via automated SMS' } },
        tags: [...(input.lead?._raw?.tags || []), 'opted-out', 'nexus-optout'],
      }),
    });
    if (response.ok) updateResult = { success: true, error: null };
    else { const errText = await response.text(); throw new Error(`GHL error: ${response.status} ${errText}`); }

    try {
      await fetch(`${config.baseUrl}/contacts/${leadId}/notes`, {
        method: 'POST',
        headers: config.headers,
        body: JSON.stringify({ body: '[AI] Customer opted out via SMS. Sequence stopped.' }),
      });
    } catch (e) { /* non-critical */ }
  } else {
    // Activix PUT
    const response = await fetch(`${config.baseUrl}/leads/${leadId}`, {
      method: 'PUT',
      headers: config.headers,
      body: JSON.stringify({ result: 'lost', comment: '[AI] Customer opted out via SMS. Sequence stopped.' }),
    });
    if (response.ok) updateResult = { success: true, error: null };
    else { const errText = await response.text(); throw new Error(`Activix error: ${response.status} ${errText}`); }
  }
} catch (err) {
  updateResult = { success: false, error: err.message };
}

return [{ json: { ...input, _crmOptOutResult: updateResult } }];

const input = $input.first().json;
const leadId = input.leadId;
const staticData = $getWorkflowStaticData('global');
if (!staticData.cadenceTimers) staticData.cadenceTimers = {};
staticData.cadenceTimers[leadId] = { lastReplyAt: new Date().toISOString(), cooldownHours: 72, intent: input.intentClassification?.intent || input.intent || 'unknown' };
return [{ json: { status:'cadence_reset', leadId, cooldownUntil: new Date(Date.now() + 72*60*60*1000).toISOString() } }];
